/* ============================================================
   Start to Scale Financial Management — Design Tokens
   Van chaos naar controle. Van onderbuik naar inzicht.
   Van start-up naar serieuze scale-up.

   Version:  1.0.0
   Date:     2026-06-01
   Brand:    Start to Scale Financial Management
   Primary:  Midnight Navy (#0A1F3D)
   Accent:   Amber (#E8A33D)

   All values derive from charter.json. When charter.json changes,
   regenerate this file in the same promotion step.
   ============================================================ */

:root {

  /* -- Primary Palette ---------------------------------------- */
  --brand-dark:          #0B0E14;
  --brand-primary:       #0A1F3D;     /* Midnight Navy */
  --brand-primary-alt:   #1A3358;     /* Lighter navy for hover/secondary surfaces */
  --brand-accent:        #E8A33D;     /* Amber — signal/CTA, use sparingly */
  --brand-accent-hover:  #D08F2D;
  --brand-text:          #0A1F3D;
  --brand-text-light:    #6B7280;
  --brand-background:    #FAF8F3;     /* Warm off-white, paper */
  --brand-background-alt:#FFFFFF;

  /* -- Navy Scale --------------------------------------------- */
  --navy-50:             #EEF1F7;
  --navy-100:            #D7DEEA;
  --navy-200:            #B0BCD0;
  --navy-300:            #788BAF;
  --navy-400:            #4A6390;
  --navy-500:            #2D4670;
  --navy-600:            #1A3358;
  --navy-700:            #15315A;
  --navy-800:            #0A1F3D;     /* = --brand-primary */
  --navy-900:            #050F1F;

  /* -- Amber Scale -------------------------------------------- */
  --amber-50:            #FCF4E5;
  --amber-100:           #FAEAD0;
  --amber-200:           #F6DAAE;
  --amber-300:           #F1C786;
  --amber-400:           #EDB55E;
  --amber-500:           #E8A33D;     /* = --brand-accent */
  --amber-600:           #D08F2D;
  --amber-700:           #B27921;
  --amber-800:           #8E6017;
  --amber-900:           #6D4A0F;

  /* -- Brand Color Scale (aliases) ---------------------------- */
  --brand-900:           var(--navy-900);
  --brand-800:           var(--navy-800);    /* = --brand-primary */
  --brand-700:           var(--navy-700);
  --brand-600:           var(--navy-600);
  --brand-500:           var(--navy-500);
  --brand-400:           var(--navy-400);
  --brand-300:           var(--navy-300);
  --brand-200:           var(--navy-200);
  --brand-100:           var(--navy-100);
  --brand-50:            var(--navy-50);

  /* -- Accent Color Scale (aliases) --------------------------- */
  --accent-900:          var(--amber-900);
  --accent-700:          var(--amber-700);
  --accent-500:          var(--amber-500);   /* = --brand-accent */
  --accent-300:          var(--amber-300);
  --accent-100:          var(--amber-100);
  --accent-50:           var(--amber-50);

  /* -- Neutral Scale ------------------------------------------ */
  --neutral-50:          #FAF8F3;     /* Paper */
  --neutral-100:         #F0EEE9;
  --neutral-200:         #E5E2DA;
  --neutral-300:         #C9C5BB;
  --neutral-400:         #ACA89C;
  --neutral-500:         #8E8A7E;
  --neutral-600:         #6B7280;
  --neutral-700:         #4D5460;
  --neutral-800:         #2D3340;
  --neutral-900:         #181C24;
  --neutral-950:         #0B0E14;
  --neutral-white:       #FFFFFF;

  /* -- Semantic Colors (palette-aligned, muted) --------------- */
  --success:             #4A7A5A;
  --success-light:       #E8F0EB;
  --warning:             #C28F3D;
  --warning-light:       #F7EDD9;
  --error:               #B85648;
  --error-light:         #F4E0DC;
  --info:                #4A6390;     /* navy-400 — info derives from brand */
  --info-light:          #E5EAF1;

  /* -- Typography --------------------------------------------- */
  --font-display:        'Newsreader', Georgia, 'Times New Roman', serif;
  --font-heading:        'Newsreader', Georgia, 'Times New Roman', serif;
  --font-body:           'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', system-ui, sans-serif;
  --font-mono:           'JetBrains Mono', 'SF Mono', Consolas, 'Liberation Mono', monospace;

  /* -- Type Scale --------------------------------------------- */
  --text-display-xl:     3.5rem;      /* 56px */
  --text-display-lg:     2.75rem;     /* 44px */
  --text-display-md:     2.25rem;     /* 36px */
  --text-display-sm:     1.75rem;     /* 28px */
  --text-h1:             2rem;        /* 32px */
  --text-h2:             1.625rem;    /* 26px */
  --text-h3:             1.375rem;    /* 22px */
  --text-h4:             1.125rem;    /* 18px */
  --text-body-lg:        1.0625rem;   /* 17px */
  --text-body:           1rem;        /* 16px */
  --text-body-sm:        0.875rem;    /* 14px */
  --text-caption:        0.75rem;     /* 12px */
  --text-overline:       0.6875rem;   /* 11px */
  --text-micro:          0.625rem;    /* 10px */

  /* -- Line Heights ------------------------------------------- */
  --leading-tight:       1.1;
  --leading-snug:        1.25;
  --leading-display:     1.15;
  --leading-heading:     1.25;
  --leading-body:        1.7;
  --leading-body-sm:     1.55;
  --leading-caption:     1.4;

  /* -- Letter Spacing ----------------------------------------- */
  --tracking-tightest:   -0.04em;
  --tracking-tight:      -0.02em;
  --tracking-snug:       -0.01em;
  --tracking-normal:     0;
  --tracking-wide:       0.04em;
  --tracking-wider:      0.08em;
  --tracking-widest:     0.18em;       /* Overlines, FINANCIAL MANAGEMENT caption */

  /* -- Font Weights ------------------------------------------- */
  --weight-light:        300;
  --weight-regular:      400;
  --weight-medium:       500;          /* Newsreader display default */
  --weight-semibold:     600;
  --weight-bold:         700;

  /* -- Spacing Scale (4px base) ------------------------------- */
  --space-1:   0.25rem;
  --space-2:   0.5rem;
  --space-3:   0.75rem;
  --space-4:   1rem;
  --space-5:   1.25rem;
  --space-6:   1.5rem;
  --space-8:   2rem;
  --space-10:  2.5rem;
  --space-12:  3rem;
  --space-16:  4rem;
  --space-20:  5rem;
  --space-24:  6rem;
  --space-32:  8rem;

  /* -- Border Radius ------------------------------------------ */
  --radius-sm:   4px;
  --radius-md:   6px;
  --radius-lg:   8px;
  --radius-xl:   12px;
  --radius-2xl:  16px;
  --radius-full: 9999px;

  /* -- Shadows (subtle, advisory-firm restraint) -------------- */
  --shadow-sm:   0 1px 2px rgba(10,31,61,0.05);
  --shadow-md:   0 2px 8px rgba(10,31,61,0.08);
  --shadow-lg:   0 6px 20px rgba(10,31,61,0.10);
  --shadow-xl:   0 12px 32px rgba(10,31,61,0.12);

  /* -- Transitions -------------------------------------------- */
  --ease-out:        cubic-bezier(0.16, 1, 0.3, 1);
  --ease-in-out:     cubic-bezier(0.4, 0, 0.2, 1);
  --duration-fast:   120ms;
  --duration-normal: 240ms;
  --duration-slow:   480ms;

  /* -- Brand Motif (Three Steps) ------------------------------ */
  --motif-line-color:       var(--brand-primary);
  --motif-line-color-light: var(--navy-300);
  --motif-accent-color:     var(--brand-accent);
  --motif-line-weight:      1.5px;
  --motif-bar-width:        12px;
  --motif-bar-gap:          6px;
  --motif-step-ratio-1:     1;
  --motif-step-ratio-2:     1.8;
  --motif-step-ratio-3:     2.6;

  /* -- Layout ------------------------------------------------- */
  --content-width:    720px;
  --content-wide:     960px;
  --content-max:      1280px;
}

/* ============================================================
   UTILITY CLASSES
   ============================================================ */

.font-display { font-family: var(--font-display); font-weight: var(--weight-medium); letter-spacing: var(--tracking-tight); }
.font-body    { font-family: var(--font-body);    font-weight: var(--weight-regular); }
.font-mono    { font-family: var(--font-mono);    font-weight: var(--weight-regular); }

.text-primary   { color: var(--brand-primary); }
.text-accent    { color: var(--brand-accent); }
.text-light     { color: var(--brand-text-light); }
.bg-primary     { background: var(--brand-primary); color: var(--brand-background); }
.bg-paper       { background: var(--brand-background); }
.bg-surface-alt { background: var(--brand-background-alt); }

.overline {
  font-family: var(--font-body);
  font-size: var(--text-overline);
  font-weight: var(--weight-medium);
  letter-spacing: var(--tracking-widest);
  text-transform: uppercase;
  color: var(--brand-text-light);
}

.divider {
  height: 1.5px;
  background: linear-gradient(to right, var(--brand-primary) 0%, var(--brand-primary) 90%, var(--brand-accent) 90%, var(--brand-accent) 100%);
  border: none;
  margin: var(--space-8) 0;
}

.btn-primary {
  font-family: var(--font-body);
  font-weight: var(--weight-medium);
  font-size: var(--text-body-sm);
  letter-spacing: var(--tracking-wide);
  padding: var(--space-3) var(--space-6);
  background: var(--brand-primary);
  color: var(--brand-background);
  border: 1.5px solid var(--brand-primary);
  border-radius: var(--radius-sm);
  cursor: pointer;
  transition: background var(--duration-normal) var(--ease-out);
}
.btn-primary:hover { background: var(--brand-primary-alt); }

.btn-accent {
  font-family: var(--font-body);
  font-weight: var(--weight-medium);
  font-size: var(--text-body-sm);
  letter-spacing: var(--tracking-wide);
  padding: var(--space-3) var(--space-6);
  background: var(--brand-accent);
  color: var(--brand-primary);
  border: 1.5px solid var(--brand-accent);
  border-radius: var(--radius-sm);
  cursor: pointer;
  transition: background var(--duration-normal) var(--ease-out);
}
.btn-accent:hover { background: var(--brand-accent-hover); }

.btn-ghost {
  font-family: var(--font-body);
  font-weight: var(--weight-medium);
  font-size: var(--text-body-sm);
  padding: var(--space-3) var(--space-6);
  background: transparent;
  color: var(--brand-primary);
  border: 1.5px solid var(--brand-primary);
  border-radius: var(--radius-sm);
}

.card {
  background: var(--brand-background-alt);
  border: 1px solid var(--neutral-200);
  border-radius: var(--radius-md);
  padding: var(--space-6);
}

.badge {
  display: inline-block;
  font-family: var(--font-body);
  font-size: var(--text-caption);
  font-weight: var(--weight-medium);
  letter-spacing: var(--tracking-wide);
  text-transform: uppercase;
  padding: 2px 8px;
  border-radius: var(--radius-sm);
}
.badge-success { background: var(--success-light); color: var(--success); }
.badge-warning { background: var(--warning-light); color: var(--warning); }
.badge-error   { background: var(--error-light);   color: var(--error); }
.badge-info    { background: var(--info-light);    color: var(--info); }

/* ============================================================
   DARK / LIGHT SURFACE TOKENS
   ============================================================ */

@media (prefers-color-scheme: dark) {
  :root {
    --surface:         var(--navy-900);
    --surface-raised:  var(--navy-800);
    --text-primary:    var(--neutral-50);
    --text-secondary:  var(--neutral-300);
    --text-tertiary:   var(--neutral-500);
    --border:          var(--navy-700);
    --border-subtle:   var(--navy-800);
  }
}

@media (prefers-color-scheme: light) {
  :root {
    --surface:         var(--brand-background);
    --surface-raised:  var(--brand-background-alt);
    --text-primary:    var(--brand-primary);
    --text-secondary:  var(--neutral-600);
    --text-tertiary:   var(--neutral-500);
    --border:          var(--neutral-200);
    --border-subtle:   var(--neutral-100);
  }
}
